"use strict";parserFactory.register("truyenyy.com",()=>new TruyenyyParser);class TruyenyyParser extends Parser{constructor(){super()}getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,TruyenyyParser.extractPartialChapterList,TruyenyyParser.getUrlsOfTocPages,t)}static extractPartialChapterList(e){let t="",r=[];for(let l of e.querySelectorAll("table.table a"))"table-chap-title"===l.className&&(l.textContent=t+": "+l.textContent.trim(),r.push(l)),t=l.textContent.trim();return r.map(e=>util.hyperLinkToChapter(e))}static getUrlsOfTocPages(e){let t=[];if(null!=e.querySelector("ul.pagination")){let r=[...e.querySelectorAll("a.page-link")].map(e=>e.href).filter(e=>e.includes("?p=")),l=r.map(e=>parseInt(e.split("?p=")[1])).reduce((e,t)=>Math.max(e,t),-1);if(1<l){let e=r[0].split("?p=")[0];for(let r=2;r<=l;++r)t.push(`${e}?p=${r}`)}}return t}findContent(e){return e.querySelector("div#id_chap_content div.inner")}extractTitleImpl(e){return e.querySelector("div.novel-info .name")}extractAuthor(e){let t=e.querySelector("div.novel-info .author a");return null===t?super.extractAuthor(e):t.textContent}findChapterTitle(e){return e.querySelector("div#id_chap_content .chapter-title")}findCoverImageUrl(e){let t=e.querySelector("div.novel-info img");return null===t?t:t.getAttribute("data-src")}}